using System;

var span = (stackalloc nint[4]);
span[0] = 10;
span[1] = 20;
span[2] = 30;
span[3] = 40;

Console.WriteLine($"Type: Span<{typeof(nint).Name}>");
Console.WriteLine($"Length: {span.Length}");
for (int i = 0; i < span.Length; i++)
    Console.WriteLine($"  [{i}] = {span[i]}");

