uspan[0] = 100;
uspan[1] = 200;
uspan[2] = 300;

Console.WriteLine($"Type: Span<{typeof(nuint).Name}>");
Console.WriteLine($"Length: {uspan.Length}");
for (int i = 0; i < uspan.Length; i++)
    Console.WriteLine($"  [{i}] = {uspan[i]}");
EOF
